1	export type Cell = [x: number, y: number];
2	
3	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const livesNextGeneration = (isAlive: boolean, liveNeighbors: number): boolean =>
6	  isAlive ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;
7	
8	const neighborsOf = ([x, y]: Cell): Cell[] => [
9	  [x - 1, y - 1], [x, y - 1], [x + 1, y - 1],
10	  [x - 1, y    ],             [x + 1, y    ],
11	  [x - 1, y + 1], [x, y + 1], [x + 1, y + 1],
12	];
13	
14	type NeighborTally = { readonly cell: Cell; readonly liveNeighbors: number };
15	
16	const tallyNeighborInfluences = (cells: readonly Cell[]): Map<string, NeighborTally> => {
17	  const tallies = new Map<string, NeighborTally>();
18	  for (const cell of cells) {
19	    for (const neighbor of neighborsOf(cell)) {
20	      const k = keyOf(neighbor);
21	      const prior = tallies.get(k)?.liveNeighbors ?? 0;
22	      tallies.set(k, { cell: neighbor, liveNeighbors: prior + 1 });
23	    }
24	  }
25	  return tallies;
26	};
27	
28	export function nextGeneration(cells: readonly Cell[]): Cell[] {
29	  const alive = new Set(cells.map(keyOf));
30	  const next: Cell[] = [];
31	  for (const [k, { cell, liveNeighbors }] of tallyNeighborInfluences(cells)) {
32	    if (livesNextGeneration(alive.has(k), liveNeighbors)) {
33	      next.push(cell);
34	    }
35	  }
36	  return next;
37	}
