4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 Underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 Survival: live cell with 2 neighbors survives — middle of vertical 3-in-a-row keeps (0,1)", () => {
15	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
16	    expect(next).toContainEqual([0, 1]);
17	  });
18	  it("Rule 3 Overpopulation: center of full 3x3 dies — next gen excludes (1,1)", () => {
19	    const full3x3: Cell[] = [[0,0],[1,0],[2,0],[0,1],[1,1],[2,1],[0,2],[1,2],[2,2]];
20	    expect(nextGeneration(full3x3)).not.toContainEqual([1, 1]);
21	  });
22	  it("Rule 4 Reproduction: dead cell with exactly 3 neighbors becomes alive — L-shape produces (1,1)", () => {
23	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
24	  });
25	  it("Block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same set", () => {
26	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
