const tallyNeighborInfluences = (cells: readonly Cell[]): Map<string, NeighborTally> => {
  const tallies = new Map<string, NeighborTally>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = keyOf(neighbor);
      const priorCount = tallies.get(key)?.liveNeighbors ?? 0;
      tallies.set(key, { cell: neighbor, liveNeighbors: priorCount + 1 });
    }
  }
  return tallies;
};

export function nextGeneration(cells: readonly Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(keyOf));
  const survivors: Cell[] = [];
  for (const [key, { cell, liveNeighbors }] of tallyNeighborInfluences(cells)) {
    if (livesNextGeneration(aliveKeys.has(key), liveNeighbors)) {
      survivors.push(cell);
    }
  }
  return survivors;
}
